func TestNovelGraphExportBuildsRelationshipEdges(t *testing.T) {
	cases := []struct {
		name              string
		wantRelationships []string
	}{
		{name: "client registrant issue lobbyist and government edges", wantRelationships: []string{"client_registrant", "client_issue", "registrant_lobbyist", "client_government_entity"}},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			dbPath := newLDANovelTestDB(t)
			seedLDANovelRecord(t, dbPath, "filings", "f1", `{"id":1,"filing_uuid":"f1","filing_year":2024,"filing_period":"mid_year","client":{"name":"Boeing Company"},"registrant":{"name":"Akin Gump"},"lobbying_activities":[{"general_issue_code":"DEF","lobbyists":[{"lobbyist":{"first_name":"Alice","last_name":"Lobby"}}],"government_entities":[{"id":1,"name":"Department of Defense"}]}]}`)
			flags := &rootFlags{asJSON: true}
			rows := runLDANovelRows(t, newNovelGraphExportCmd(flags), "--db", dbPath, "--client", "Boeing")
			got := map[string]bool{}
			for _, row := range rows {
				got[row["relationship"].(string)] = true
			}
			for _, rel := range tc.wantRelationships {
				if !got[rel] {
					t.Fatalf("missing relationship %q in %#v", rel, rows)
				}
			}
		})
	}
}

